        /**
         * Migrates bindings from deprecated commands to their equivalent commands:
         * - FLIP_OR_ANSWER_RECOMMENDED -> FLIP_OR_ANSWER_EASE3
         * - FLIP_OR_ANSWER_BETTER_THAN_RECOMMENDED -> FLIP_OR_ANSWER_EASE4
         */
        internal class MigrateAnswerButtonCommands : PreferenceUpgrade(12) {
            override fun upgrade(preferences: SharedPreferences) {
                // Migrate FLIP_OR_ANSWER_RECOMMENDED to FLIP_OR_ANSWER_EASE3
                migrateBindings(
                    preferences,
                    "binding_FLIP_OR_ANSWER_RECOMMENDED",
                    ViewerCommand.FLIP_OR_ANSWER_EASE3
                )

                // Migrate FLIP_OR_ANSWER_BETTER_THAN_RECOMMENDED to FLIP_OR_ANSWER_EASE4
                migrateBindings(
                    preferences,
                    "binding_FLIP_OR_ANSWER_BETTER_THAN_RECOMMENDED",
                    ViewerCommand.FLIP_OR_ANSWER_EASE4
                )
            }

            private fun migrateBindings(
                preferences: SharedPreferences,
                oldPreferenceKey: String,
                targetCommand: ViewerCommand
            ) {
                if (!preferences.contains(oldPreferenceKey)) {
                    Timber.v("No preference to migrate for '%s'", oldPreferenceKey)
                    return
                }

                try {
                    // Get the bindings from the old command
                    val oldBindings = MappableBinding.fromPreferenceString(oldPreferenceKey)

                    if (oldBindings.isEmpty()) {
                        Timber.v("No bindings to migrate from '%s'", oldPreferenceKey)
                        return
                    }

                    Timber.i("Migrating %d bindings from '%s' to '%s'", 
                        oldBindings.size, oldPreferenceKey, targetCommand.preferenceKey)

                    // Add each binding to the target command
                    oldBindings.forEach { binding ->
                        targetCommand.addBindingAtEnd(preferences, binding)
                    }
                } finally {
                    // Remove the old preference key
                    Timber.v("Removing old preference key: '%s'", oldPreferenceKey)
                    preferences.edit { remove(oldPreferenceKey) }
                }
            }
        }
    }
}"}

